    }

    if (cart.tax < 0) {
        return { success: false, error: "La taxe ne peut pas être négative" };
    }

    const total = cart.items.reduce((accumulator, item) => {
        if (item.price === undefined) {
            return { success: false, error: "Un article n'a pas de prix défini" };
        }
        return accumulator + item.price * cart.tax;
    }, 0);

    if ((total as Result<number>).error) {
